function e(n,t=2){return n==null||Number.isNaN(Number(n))?"—":Number(n).toLocaleString("en-US",{minimumFractionDigits:t,maximumFractionDigits:t})}function o(n){if(n==null)return"—";const t=Number(n),r=Math.abs(t)>=1e3?2:Math.abs(t)>=1?3:6;return t.toLocaleString("en-US",{minimumFractionDigits:r,maximumFractionDigits:r})}function u(n,t=2){if(n==null)return"—";const r=Number(n);return`${r>=0?"+":""}${r.toFixed(t)}%`}function a(n,t=2){return n==null?"—":"$"+e(n,t)}function c(n){if(n==null)return"—";const t=Number(n),r=Math.abs(t);return r>=1e9?(t/1e9).toFixed(2)+"B":r>=1e6?(t/1e6).toFixed(2)+"M":r>=1e3?(t/1e3).toFixed(1)+"K":t.toFixed(0)}function m(n){return n==null?"":Number(n)>=0?"up":"down"}function s(n){if(!n)return"—";const t=Math.floor((Date.now()-Number(n))/1e3);if(t<60)return t+"s ago";const r=Math.floor(t/60);if(r<60)return r+"m ago";const i=Math.floor(r/60);return i<24?i+"h ago":Math.floor(i/24)+"d ago"}function f(n){return n?new Date(Number(n)).toLocaleString():"—"}export{u as a,s as b,c,e as n,o as p,m as s,f as t,a as u};
